const items = $input.all();
let users = [];
for (const it of items) {
  const j = it.json;
  if (Array.isArray(j)) users.push(...j);
  else if (j && Array.isArray(j.data)) users.push(...j.data);
  else if (j && j.directories) users.push(j);
}
const sd = $getWorkflowStaticData('global');
sd.seen = sd.seen || {};
const firstRun = !sd.initialized;
const newByAlbum = {};
for (const u of users) {
  for (const dir of (u.directories || [])) {
    for (const f of (dir.files || [])) {
      if (!String(f.state || '').includes('Succeeded')) continue;
      if (sd.seen[f.id]) continue;
      sd.seen[f.id] = true;
      if (firstRun) continue;
      const album = String(dir.directory || '').split('\\').filter(Boolean).pop() || 'download';
      newByAlbum[album] = (newByAlbum[album] || 0) + 1;
    }
  }
}
sd.initialized = true;
const entries = Object.entries(newByAlbum);
if (!entries.length) return [];
const lines = entries.map(([a, n]) => `🎵 ${a} — ${n} track${n > 1 ? 's' : ''}`);
return [{ json: { message: 'Soulseek downloads finished:\n' + lines.join('\n') } }];
